/**
 * Compare a stored instant in UTC with another zoned instant.
 * 
 * @param {Temporal.PlainDateTime} naive_utc - The stored instant in UTC.
 * @param {Temporal.ZonedDateTime} other - The other zoned instant.
 * @returns {boolean} True if the stored instant is strictly before the other instant.
 */
function stored_before(naive_utc, other) {
  // Attach the UTC zone to the naive_utc PlainDateTime to make it a ZonedDateTime
  const stored_utc = naive_utc.toZonedDateTime('UTC');

  // Compare the epoch nanoseconds of the two instants
  return stored_utc.epochNanoseconds < other.epochNanoseconds;
}
