/**
 * Returns true if the naive UTC datetime is strictly before the zoned datetime in absolute time.
 * 
 * @param {Temporal.PlainDateTime} naive_utc - A naive datetime interpreted as UTC.
 * @param {Temporal.ZonedDateTime} other - A zoned datetime in any timezone.
 * @returns {boolean}
 */
function stored_before(naive_utc, other) {
  if (!(naive_utc instanceof Temporal.PlainDateTime)) throw new TypeError("naive_utc must be a Temporal.PlainDateTime");
  if (!(other instanceof Temporal.ZonedDateTime)) throw new TypeError("other must be a Temporal.ZonedDateTime");

  const instantNaive = naive_utc.toZonedDateTime(Temporal.ZonedDateTime.from({ timeZone: "UTC" }));
  const instantOther = other.toInstant();

  return instantNaive.compare(instantOther) === -1;
}
