from datetime import datetime

def dedup_by_instant(events):
    seen_instants = set()
    result = []
    for event in events:
        if isinstance(event, datetime):
            # Normalize to UTC for comparison regardless of local zone
            instant = event.astimezone.utc
        else:
            raise TypeError("All entries must be datetime objects")

        if instant not in seen_instants:
            seen_instants.add(instant)
            result.append(event)
    return result
